/**
 * Analytics event tracking for Aura Alpha launch measurement.
 *
 * Lightweight fire-and-forget utility that sends events to:
 *   - POST /api/ml/events (ML tracker pipeline)
 *   - POST /api/analytics/event (conversion/funnel tracking — public, no auth)
 *
 * Designed to be used alongside useMLTracker for non-component contexts
 * (route handlers, callbacks, etc.).
 *
 * Usage:
 *   import { track, trackEvent } from '@/utils/analytics'
 *   track('signup_complete')
 *   trackEvent('cta_click', { button: 'hero' })
 */

import { apiPost } from './api';
import { getApiBase } from './platform';

const SESSION_KEY = 'aura_ml_session_id';
const UTM_KEY = 'aura_utm_params';

function _getSessionId() {
  let sid = sessionStorage.getItem(SESSION_KEY);
  if (!sid) {
    sid = `${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
    sessionStorage.setItem(SESSION_KEY, sid);
  }
  return sid;
}

// ── UTM Parameter Capture ───────────────────────────────────────────
const UTM_PARAMS = ['utm_source', 'utm_medium', 'utm_campaign', 'utm_content'];

function _captureUtmParams() {
  try {
    const params = new URLSearchParams(window.location.search);
    const utm = {};
    let hasUtm = false;
    UTM_PARAMS.forEach(key => {
      const val = params.get(key);
      if (val) { utm[key] = val; hasUtm = true; }
    });
    if (hasUtm) {
      sessionStorage.setItem(UTM_KEY, JSON.stringify(utm));
    }
  } catch { /* silent */ }
}

export function getUtmParams() {
  try {
    return JSON.parse(sessionStorage.getItem(UTM_KEY) || '{}');
  } catch { return {}; }
}

// Capture UTMs on first load
_captureUtmParams();

// ── Conversion / Funnel Event Tracking (public endpoint) ────────────

/**
 * Track a conversion/funnel event via POST /api/analytics/event.
 * Fire-and-forget — no auth required, never blocks UI.
 */
export function trackEvent(eventName, properties = {}) {
  if (import.meta.env.DEV) {
    console.log('[analytics:event]', eventName, properties);
  }
  const payload = {
    event: eventName,
    properties: { ...getUtmParams(), ...properties },
    session_id: _getSessionId(),
    timestamp: new Date().toISOString(),
    url: window.location.href,
    referrer: document.referrer || '',
  };
  // Fire-and-forget fetch — bypasses api() auth/retry logic
  const base = getApiBase();
  fetch(`${base}/analytics/event`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(payload),
    keepalive: true,
  }).catch(() => {}); // silent — analytics must never break UI
}

// ── ML Pipeline Tracking (auth-aware) ───────────────────────────────

/**
 * Track an analytics event via the ML pipeline. Fire-and-forget — never blocks UI.
 */
export function track(event, properties = {}) {
  if (import.meta.env.DEV) {
    console.log('[analytics]', event, properties);
  }

  apiPost('/ml/events', {
    event_type: event,
    payload: properties,
    session_id: _getSessionId(),
    timestamp: Date.now() / 1000,
  }).catch(() => {}); // silent — analytics must never break UI
}

// ── Named Event Helpers ─────────────────────────────────────────────

export function trackSignupComplete() {
  track('signup_complete');
}

export function trackFirstStrategyView(strategyName) {
  track('first_strategy_view', { strategy: strategyName });
}

export function trackFirstBacktestRun(params = {}) {
  track('first_backtest_run', params);
}

export function trackPaperModeActivated() {
  track('paper_mode_activated');
}

export function trackUpgradeStart(plan) {
  track('upgrade_start', { plan });
}

export function trackPageView(path) {
  track('page_view', { path });
}

export function trackRegisterStart() {
  track('register_start');
}

export function trackRegisterComplete(email) {
  track('register_complete', { email });
}

export function trackCheckoutStart(tier, billing) {
  track('checkout_start', { tier, billing });
}
